\begin{center}
    \Huge\textbf{Světlo}
\end{center}

\begin{tcolorbox}[colback=blue!5!white,colframe=blue!75!black,title=\textbf{Co je to světlo?}]
\begin{itemize}
    \item Je to fyzikální děj, který působí na naše oči a \textbf{umožňuje nám vidět} okolní svět.
    \item Ze zdroje se šíří \textbf{přímočaře} (v rovných světelných paprscích).
    \item Předměty vidíme jen tehdy, když z nich světlo dopadne do našeho oka.
\end{itemize}
\end{tcolorbox}

\vspace{0.1cm}
\subsection*{Zdroje světla}
\begin{multicols}{2}
\textbf{1. Přirozené zdroje}
\begin{itemize}
    \item \faSun\ Slunce, hvězdy
    \item \faFire\ Oheň, blesk
    \item \faBug\ Světlušky (bioluminiscence)
\end{itemize}
\columnbreak
\textbf{2. Umělé zdroje}
\begin{itemize}
    \item \faLightbulb\ Žárovka, LED
    \item \faBolt\ Laser
    \item \faMobile\ Displej mobilu
\end{itemize}
\end{multicols}

\vspace{0.1cm}
\subsection*{Optická prostředí (Kudy světlo projde?)}
\begin{itemize}
    \item \textbf{Průhledné} prostředí (Vzduch, čiré sklo, vakuum) – světlo projde čistě, vidíme ostře.
    \item \textbf{Průsvitné} prostředí (Mlha, matné sklo, papír) – světlo projde, ale rozptýlí se, vidíme neostře.
    \item \textbf{Neprůhledné} prostředí (Dřevo, zeď, kov) – světlo neprojde, odrazí se nebo se pohltí.
\end{itemize}

\vspace{0.1cm}
\begin{tcolorbox}[colback=green!5!white,colframe=green!50!black,title=\textbf{Rychlost světla}]
Světlo je nejrychlejší věc ve vesmíru. Ve vakuu a ve vzduchu letí rychlostí:
\begin{center}
    \Large\textbf{c = 300 000 km/s}
\end{center}
\textit{(Za 1 sekundu by světlo obletělo Zemi 7,5krát.)}
\end{tcolorbox}

\vspace{0.1cm}
\begin{tcolorbox}[colback=red!5!white,colframe=red!60!black,title=\textbf{Světelný rok (ly)}]
\begin{itemize}
    \item \textbf{POZOR!} Není to jednotka času, ale \textbf{VZDÁLENOSTI}.
    \item Je to dráha, kterou urazí světlo za 1 rok.
    \item Používá se v astronomii k měření vzdáleností mezi hvězdami.
\end{itemize}
\end{tcolorbox}

